parameters.jsCode:
// Récupération de toutes les sorties Groq
const groqItems = $input.all();

// Récupération des angles depuis le nœud Préserver contexte
const contexteItems = $('Préserver contexte').all();

// Parsing des réponses Groq et jointure avec les angles
const angles = groqItems.map((item, index) => {
  const raw = item.json.choices?.[0]?.message?.content ?? '{"sources":[]}';
  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    parsed = { sources: [], erreur_parsing: raw };
  }

  const contexte = contexteItems[index]?.json ?? {};

  return {
    code: contexte._angle_code || 'inconnu',
    libelle: contexte._angle_libelle || 'inconnu',
    requete: contexte._angle_requete || 'inconnu',
    sources: parsed.sources || [],
    erreur: parsed.erreur_parsing || null
  };
});

// Date et numéro de semaine ISO
const now = new Date();
const year = now.getFullYear();
const week = getISOWeek(now);
const semaine = `${year}-W${String(week).padStart(2, '0')}`;
const dateIso = now.toISOString().slice(0, 10);

function getISOWeek(d) {
  const target = new Date(d.valueOf());
  const dayNr = (d.getDay() + 6) % 7;
  target.setDate(target.getDate() - dayNr + 3);
  const firstThursday = target.valueOf();
  target.setMonth(0, 1);
  if (target.getDay() !== 4) {
    target.setMonth(0, 1 + ((4 - target.getDay()) + 7) % 7);
  }
  return 1 + Math.ceil((firstThursday - target) / 604800000);
}

// Construction du markdown
const marqueur = { rempli: '✔', partiel: '~', manque: '✘' };

let md = `---\n`;
md += `type: synthese_veille\n`;
md += `semaine: ${semaine}\n`;
md += `date: ${dateIso}\n`;
md += `angles: [${angles.map(a => a.code).join(', ')}]\n`;
md += `tags:\n  - veille\n  - synthese\n---\n\n`;
md += `# Synthèse de veille, semaine ${semaine}\n\n`;

const rejets = [];

for (const angle of angles) {
  md += `## Angle ${angle.code}, ${angle.libelle}\n\n`;
  md += `Requête, \`${angle.requete}\`.\n\n`;

  if (angle.erreur) {
    md += `> Parsing en échec, contenu brut à examiner manuellement.\n\n`;
    md += `\`\`\`\n${angle.erreur}\n\`\`\`\n\n`;
    continue;
  }

  const conservees = angle.sources.filter(s => s.conservee);
  const rejetees = angle.sources.filter(s => !s.conservee);

  if (conservees.length === 0) {
    md += `Aucune source conservée pour cet angle cette semaine.\n\n`;
  } else {
    for (const s of conservees) {
      md += `### ${s.titre}\n\n`;
      md += `- Lien, ${s.url}\n`;
      md += `- Fiabilité, `;
      md += `1${marqueur[s.criteres.c1]} `;
      md += `2${marqueur[s.criteres.c2]} `;
      md += `3${marqueur[s.criteres.c3]} `;
      md += `4${marqueur[s.criteres.c4]} `;
      md += `5${marqueur[s.criteres.c5]}\n`;
      const just = Object.entries(s.justifications || {})
        .filter(([_, v]) => v && v.trim() !== '')
        .map(([k, v]) => `  - ${k}, ${v}`);
      if (just.length > 0) {
        md += `- Justifications,\n${just.join('\n')}\n`;
      }
      md += `- Résumé, ${s.resume}\n\n`;
    }
  }

  for (const s of rejetees) {
    rejets.push({ url: s.url, angle: angle.code, raison: s.raison_rejet || 'non précisé' });
  }
}

if (rejets.length > 0) {
  md += `## Sources écartées\n\n`;
  for (const r of rejets) {
    md += `- ${r.url}, angle ${r.angle}, ${r.raison}\n`;
  }
  md += '\n';
}

// Nom du fichier
const nomFichier = `${semaine}.md`;

return [{
  json: { nomFichier, semaine },
  binary: {
    data: {
      data: Buffer.from(md, 'utf-8').toString('base64'),
      mimeType: 'text/markdown',
      fileName: nomFichier
    }
  }
}];
